import React from 'react';
import { useLocation } from 'react-router-dom';

export function MyTrip() {
  // Get the result data from the location state
  const location = useLocation();
  const tripResult = location.state?.tripResult;

  return (
    <div className="py-8 w-11/12 mx-auto text-white bg-gray-800 rounded-lg shadow-md">
      <h1 className="text-3xl font-bold text-center mb-6">Your Trip Plan</h1>

      {/* Display trip result */}
      {tripResult ? (
        <div className="text-center text-lg">
          <p>{tripResult}</p>
        </div>
      ) : (
        <p>No trip plan available.</p>
      )}
    </div>
  );
}
